diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 48a8627ab63e..d773f44025e3 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -10349,7 +10349,10 @@ BoUpSLP::getEntryCost(const TreeEntry *E, ArrayRef<Value *> VectorizedVals,
               It != MinBWs.end()) {
             auto UserBWIt = MinBWs.find(EI.UserTE);
             Type *UserScalarTy =
-                EI.UserTE->getOperand(EI.EdgeIdx).front()->getType();
+                (EI.EdgeIdx < EI.UserTE->getNumOperands() &&
+                 !EI.UserTE->getOperand(EI.EdgeIdx).empty())
+                    ? EI.UserTE->getOperand(EI.EdgeIdx).front()->getType()
+                    : ScalarTy;
             if (UserBWIt != MinBWs.end())
               UserScalarTy = IntegerType::get(ScalarTy->getContext(),
                                               UserBWIt->second.first);
@@ -15074,7 +15077,11 @@ BoUpSLP::vectorizeTree(const ExtraValueToDebugLocsMap &ExternallyUsedValues,
   for (const TreeEntry *E : PostponedNodes) {
     auto *TE = const_cast<TreeEntry *>(E);
     if (auto *VecTE = getTreeEntry(TE->Scalars.front()))
-      if (VecTE->isSame(TE->UserTreeIndices.front().UserTE->getOperand(
+      if (TE->UserTreeIndices.front().EdgeIdx <
+              TE->UserTreeIndices.front().UserTE->getNumOperands() &&
+          !TE->UserTreeIndices.front().UserTE->getOperand(
+               TE->UserTreeIndices.front().EdgeIdx)
+               .empty() && VecTE->isSame(TE->UserTreeIndices.front().UserTE->getOperand(
               TE->UserTreeIndices.front().EdgeIdx)) &&
           VecTE->isSame(TE->Scalars))
